package exercfor;

public class For1 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		int x;

		for (x = 1; x <= 10; x++) {
			System.out.println("\n " + x);
		}
		for (x = 10; x >= 1; x--) {
			System.out.println(" " + x);

		}

		for (x = 101; x <= 110; x++) {
			System.out.println(" " + x);
		}
	}

}
